head.script:
/**
 * 화 면 명 : 이자율등록자동생성
 * 메뉴경로 : 회계/관리회계/실적관리/실적집계/자산비용관리/이자율등록
 * ASIS경로 : /debis/dongwon-debis-engine/src/main/webapp/ac/co/rsltsmgnt/rsltsaggr/co_403_01_04p.jsp
 * 작 성 자 : 배기원
 * 작 업 일 : 2025-10-13
 * 작업내용 :
 *    1. 화면세팅
 *    2. 초기세팅(UDC)
 *    3. 스크립트 TOBE전환
 *    4. 기능확인(버튼)
 * 참고사항 :
 * 수정이력 :
 *    - 2025-10-13      배기원    최초작성
 */

//부모창에서 받은 파라메터
scwin.params;

/**
 * TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
 */
scwin.onpageload = function() {
    scwin.params = $c.data.getParameter();
};

/**
 * UDC값 초기화(scwin.onpageload 이후 세팅됨)
 */
scwin.onUdcCompleted = function() {
    //      $p.setTimeout(function() {
    scwin.f_SetDsetHeader();
    //      }, {"delay":50});
};

/**
 * 데이터셋의 헤더를 설정
 */
scwin.f_SetDsetHeader = function() {
    if (!$c.util.isEmpty(scwin.params["stdYm"])) {
        dma_master.set("stdYm", scwin.params["stdYm"]);
    }
};

/**
 * 생성
 */
scwin.f_Create = async function () {
    //생성조건 입력여부 및 형식 체크
    if (! await $c.gus.cfValidate([ed_stdYm, ed_YmFrom, ed_YmTo])) {
        return;
    }

    //반영할 기간의 시작년월이 기준년월과 같은 지 체크
    if (ed_stdYm.getValue() == ed_YmFrom.getValue()) {
        await $c.win.alert("기준년월과 반영할 기간의 시작년월이 같습니다.");
        ed_YmFrom.focus();
        return;
    }

    //반영할 기간의 종료년월이 기준년월과 같은 지 체크
    if (ed_stdYm.getValue() == ed_YmTo.getValue()) {
        await $c.win.alert("기준년월과 반영할 기간의 종료년월이 같습니다.");
        ed_YmTo.focus();
        return;
    }
    //기준년월이 반영할 기간의 사이에 있는 지 체크
    if (ed_stdYm.getValue() > ed_YmFrom.getValue()
        && ed_stdYm.getValue() < ed_YmTo.getValue()) {
        await $c.win.alert("기준년월이 반영할 기간의 사이에 있습니다.");
        ed_YmFrom.focus();
        return;
    }
    //반영할 기간의 시작과 끝을 비교
    if (ed_YmFrom.getValue() > ed_YmTo.getValue()) {
        await $c.win.alert("반영할 기간의 범위가 잘못되었습니다.");
        ed_YmFrom.focus();
        return;
    }

    if (await $c.win.confirm("반영할 기간의 기존 자료는 삭제됩니다.<BR>계속하시겠습니까?")) {
        // cfShowWaitMsg();
        dma_master.set("planRsltsClsCd", scwin.params["planRsltsClsCd"]);
        dma_master.set("coCd", scwin.params["coCd"]);

        $c.sbm.execute(sbm_master);
    }
};

scwin.sbm_master_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        $c.gus.f_cfAlertMsg("자동생성 되었습니다.");
    }
};

scwin.sbm_master_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};

/**
 * 닫기
 */
scwin.f_WinClose = function (e) {
    let rt = ["N/A"];
    $c.win.closePopup(rt);
};
